VALUES
  ('social-worker-moex-06860', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作執行過程中，預估與介入行動是一交互動態過程。因此，為有利於介入，預估應涵蓋：', '["成員的特質與潛意識的動機", "團體所處之外在環境因素", "工作者過往的工作經驗", "團體目標的設定與核對"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06861', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作最基本的價值觀為何？', '["參與及互助", "社會正義", "人有其尊嚴和價值", "平等原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06862', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據Rothman提出社區工作中，社區發展、社區計畫、社會行動等三種模式的運用，下列何者錯誤？', '["三種模式並不互斥，在實際運用上可以混合使用", "三種模式可因應社區不同的發展階段，而運用不同的工作模式", "三種模式中的社會行動模式與社會政策及社會行政的交集最多", "社區工作者不僅只熟悉社區組織實務，亦應採用政策與行政的視角協助社區"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06863', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「人的價值和尊嚴是與生俱來的」是社會工作的基本價值觀與倫理原則，其所強調的意涵為何？①無論 案主過去或目前的行為或生活狀況如何，當他們擔負起應負的責任時，社工員應對案主的尊嚴給予支持', '["包含了無條件正向的、非急迫性的關懷、接納和尊重", "社工員應避免評斷案主行為是好或壞、罪惡 或值得嘉許", "社工員強調工作倫理優先於社會互助", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06864', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作理論常借用心理學、社會學及生物學等理論，下列有關「生態系統理論」的基本假設何者正確？', '["個體發展以學習為主軸，受到環境的影響", "個體與環境間處於一種動態的平衡關係", "個人行為重視其對環境的知覺、內在認知經驗和心理感受", "個人的問題來自生活中內在的心理因素和外在的環境因素交互作用所形成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06865', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '結案是指正式結束社工員與案主的個別關係。下列有關社會個案工作過程中的結案，何者是成功的結案？', '["結案過程由社工員與案主共同討論決定", "當機構提供的服務有時間性時，社工員應處理案主分離的 感受並視需要轉介案主", "結案時社工員應與案主一同回顧處遇的過程，讓案主看到自己的成長及應努 力之處", "結案過程中案主若有依賴的需要，社工員應規劃延續性的服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06866', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '個案紀錄的格式有多種方式，如果社工員以回顧的方式，敘述案主與社工員及機構間互動的內容，並將 案主接受服務期間所發生的事情具體描述，這種紀錄格式稱為？', '["對話式紀錄", "流水帳式紀錄", "過程式紀錄", "摘要式紀錄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06867', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '生態圖是將家庭視為社會大系統的一部分，評估家庭與外界社會環境之互動關係，個案工作者在建構家 庭生態圖時，應分內部系統與外部系統。有關生態圖的建構，就外部系統而言，下列敘述何者錯誤？', '["從生態圖可判斷有關家庭的問題、需求、資源，甚至互動有關之情況", "將與案主或案主家庭有關之外部相關資源，以圓圈之遠近代表親疏遠近關係", "清楚的繪出家庭成員的性別符號與相關之基本資料，並以線條繪出代表家庭成員之間的親疏遠近關係", "以不同線條描述各個圓圈與案主或案主家庭的互動關係，通常線條愈粗就代表關係愈緊密"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06868', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「接納」（acceptance）是社會個案工作的一種基本原則，其主要意涵為？', '["贊同案主偏差態度或行為", "接受案主好的態度或行為", "接受案主真實的態度或行為", "接受案主的缺點和矛盾處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06869', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在會談的過程中，案主往往會想到那裡就說到那裡、用詞模糊或是表達的內容籠統。為了提升會談的效 果，工作者把案主所敘述的內容作一整理，邀請案主釐清整理的重點是否符合原意，這種技巧稱為「澄', '["再建構", "簡述語意", "連結", "聚焦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
